CREATE SCHEMA IF NOT EXISTS asset;

CREATE OR REPLACE FUNCTION asset.asset_create(p_row asset.asset)
 RETURNS asset.asset
 LANGUAGE plpgsql
AS $function$
BEGIN
  p_row.id := COALESCE(p_row.id, gen_random_uuid());
  p_row.tenant_id := current_setting('app.tenant_id', true);
  p_row.status := COALESCE(p_row.status, 'to_classify');
  p_row.mime_type := COALESCE(p_row.mime_type, 'image/jpeg');
  p_row.tags := COALESCE(p_row.tags, '{}');
  p_row.colors := COALESCE(p_row.colors, '{}');
  p_row.created_at := COALESCE(p_row.created_at, now());

  INSERT INTO asset.asset (id, tenant_id, path, filename, mime_type, status,
    width, height, orientation, title, description, tags, credit, saison,
    usage_hint, colors, thumb_path, created_at, classified_at)
  VALUES (p_row.id, p_row.tenant_id, p_row.path, p_row.filename, p_row.mime_type, p_row.status,
    p_row.width, p_row.height, p_row.orientation, p_row.title, p_row.description, p_row.tags,
    p_row.credit, p_row.saison, p_row.usage_hint, p_row.colors, p_row.thumb_path,
    p_row.created_at, p_row.classified_at)
  RETURNING * INTO p_row;
  RETURN p_row;
END;
$function$;
COMMENT ON FUNCTION asset.asset_create(asset.asset) IS 'Create asset — set tenant_id, defaults, INSERT + RETURNING';

CREATE OR REPLACE FUNCTION asset.asset_delete(p_id text)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_deleted int;
BEGIN
  DELETE FROM asset.asset
  WHERE id::text = p_id AND tenant_id = current_setting('app.tenant_id', true);
  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted > 0;
END;
$function$;
COMMENT ON FUNCTION asset.asset_delete(text) IS 'Delete asset by id';

CREATE OR REPLACE FUNCTION asset.asset_list(p_filter text DEFAULT NULL::text)
 RETURNS SETOF jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  IF p_filter IS NULL THEN
    RETURN QUERY
      SELECT to_jsonb(a)
      FROM asset.asset a
      WHERE a.tenant_id = current_setting('app.tenant_id', true)
      ORDER BY a.created_at DESC;
  ELSE
    RETURN QUERY EXECUTE
      'SELECT to_jsonb(a)
       FROM asset.asset a
       WHERE a.tenant_id = ' || quote_literal(current_setting('app.tenant_id', true))
       || ' AND ' || pgv.rsql_to_where(p_filter, 'asset', 'asset')
       || ' ORDER BY a.created_at DESC';
  END IF;
END;
$function$;
COMMENT ON FUNCTION asset.asset_list(text) IS 'List assets for current tenant with optional RSQL filter — enriched with thumb_path';

CREATE OR REPLACE FUNCTION asset.asset_read(p_id text)
 RETURNS asset.asset
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN (SELECT a FROM asset.asset a WHERE a.id::text = p_id AND a.tenant_id = current_setting('app.tenant_id', true));
END;
$function$;
COMMENT ON FUNCTION asset.asset_read(text) IS 'Read asset by id — returns full composite row';

CREATE OR REPLACE FUNCTION asset.asset_ui(p_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_a RECORD;
BEGIN
  -- List mode: no slug
  IF p_slug IS NULL THEN
    RETURN jsonb_build_object(
      'ui', pgv.ui_column(
        pgv.ui_heading(pgv.t('asset.nav_assets')),
        pgv.ui_table('assets', jsonb_build_array(
          pgv.ui_col('title', pgv.t('asset.col_title'), pgv.ui_link('{title}', '/asset/asset/{id}')),
          pgv.ui_col('filename', pgv.t('asset.col_filename')),
          pgv.ui_col('mime_type', pgv.t('asset.col_mime')),
          pgv.ui_col('status', pgv.t('asset.col_status'), pgv.ui_badge('{status}')),
          pgv.ui_col('orientation', pgv.t('asset.field_orientation')),
          pgv.ui_col('credit', pgv.t('asset.field_credit'))
        ))
      ),
      'datasources', jsonb_build_object(
        'assets', pgv.ui_datasource('asset://asset', 20, true, 'created_at')
      )
    );
  END IF;

  -- Detail mode
  SELECT * INTO v_a FROM asset.asset WHERE id::text = p_slug AND tenant_id = current_setting('app.tenant_id', true);
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'not_found');
  END IF;

  RETURN jsonb_build_object(
    'ui', pgv.ui_column(
      -- Header
      pgv.ui_row(
        pgv.ui_link('← ' || pgv.t('asset.nav_assets'), '/asset/'),
        pgv.ui_heading(COALESCE(v_a.title, v_a.filename))
      ),

      -- Status + type
      pgv.ui_row(
        pgv.ui_badge(v_a.status, CASE v_a.status WHEN 'classified' THEN 'success' WHEN 'to_classify' THEN 'warning' ELSE 'info' END),
        pgv.ui_text(v_a.mime_type),
        pgv.ui_text(CASE WHEN v_a.width IS NOT NULL THEN v_a.width::text || ' × ' || v_a.height::text ELSE '' END)
      ),

      -- Description
      pgv.ui_heading(pgv.t('asset.field_description'), 3),
      pgv.ui_text(COALESCE(v_a.description, '—')),

      -- Metadata
      pgv.ui_heading('Métadonnées', 3),
      pgv.ui_row(
        pgv.ui_text(pgv.t('asset.field_filename') || ': ' || v_a.filename),
        pgv.ui_text(pgv.t('asset.field_orientation') || ': ' || COALESCE(v_a.orientation, '—')),
        pgv.ui_text(pgv.t('asset.field_saison') || ': ' || COALESCE(v_a.saison, '—'))
      ),
      pgv.ui_row(
        pgv.ui_text(pgv.t('asset.field_credit') || ': ' || COALESCE(v_a.credit, '—')),
        pgv.ui_text(pgv.t('asset.field_usage_hint') || ': ' || COALESCE(v_a.usage_hint, '—'))
      ),

      -- Colors
      pgv.ui_heading(pgv.t('asset.field_colors'), 3),
      CASE WHEN cardinality(v_a.colors) > 0 THEN
        pgv.ui_row(VARIADIC ARRAY(SELECT pgv.ui_color(c) FROM unnest(v_a.colors) AS c))
      ELSE
        pgv.ui_text('—')
      END,

      -- Tags
      pgv.ui_heading(pgv.t('asset.field_tags'), 3),
      CASE WHEN cardinality(v_a.tags) > 0 THEN
        pgv.ui_row(VARIADIC ARRAY(SELECT pgv.ui_badge(t) FROM unnest(v_a.tags) AS t))
      ELSE
        pgv.ui_text('—')
      END
    )
  );
END;
$function$;
COMMENT ON FUNCTION asset.asset_ui(text) IS 'SDUI view: asset list with thumbnails/badges + detail with image, metadata, colors';

CREATE OR REPLACE FUNCTION asset.asset_update(p_row asset.asset)
 RETURNS asset.asset
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE asset.asset SET
    path        = COALESCE(NULLIF(p_row.path, ''), path),
    filename    = COALESCE(NULLIF(p_row.filename, ''), filename),
    mime_type   = COALESCE(NULLIF(p_row.mime_type, ''), mime_type),
    status      = COALESCE(NULLIF(p_row.status, ''), status),
    width       = COALESCE(p_row.width, width),
    height      = COALESCE(p_row.height, height),
    orientation = COALESCE(p_row.orientation, orientation),
    title       = COALESCE(p_row.title, title),
    description = COALESCE(p_row.description, description),
    tags        = COALESCE(p_row.tags, tags),
    credit      = COALESCE(p_row.credit, credit),
    saison      = COALESCE(p_row.saison, saison),
    usage_hint  = COALESCE(p_row.usage_hint, usage_hint),
    colors      = COALESCE(p_row.colors, colors),
    thumb_path  = COALESCE(p_row.thumb_path, thumb_path),
    classified_at = COALESCE(p_row.classified_at, classified_at)
  WHERE id = p_row.id AND tenant_id = current_setting('app.tenant_id', true)
  RETURNING * INTO p_row;
  RETURN p_row;
END;
$function$;
COMMENT ON FUNCTION asset.asset_update(asset.asset) IS 'Partial update asset by id — COALESCE preserves existing values';

