CREATE OR REPLACE FUNCTION asset.classify(p_id uuid, p_title text, p_description text DEFAULT NULL::text, p_tags text[] DEFAULT '{}'::text[], p_width integer DEFAULT NULL::integer, p_height integer DEFAULT NULL::integer, p_orientation text DEFAULT NULL::text, p_saison text DEFAULT NULL::text, p_credit text DEFAULT NULL::text, p_usage_hint text DEFAULT NULL::text, p_colors text[] DEFAULT '{}'::text[])
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_found BOOLEAN;
BEGIN
  IF p_title IS NULL OR trim(p_title) = '' THEN
    RAISE EXCEPTION '%', pgv.t('asset.err_title_required');
  END IF;

  UPDATE asset.asset SET
    title         = trim(p_title),
    description   = NULLIF(trim(COALESCE(p_description,'')), ''),
    tags          = COALESCE(p_tags, '{}'),
    width         = p_width,
    height        = p_height,
    orientation   = p_orientation,
    saison        = p_saison,
    credit        = NULLIF(trim(COALESCE(p_credit,'')), ''),
    usage_hint    = NULLIF(trim(COALESCE(p_usage_hint,'')), ''),
    colors        = COALESCE(p_colors, '{}'),
    status        = 'classified',
    classified_at = now()
  WHERE id = p_id
  RETURNING TRUE INTO v_found;

  IF NOT v_found THEN
    RAISE EXCEPTION '%', pgv.t('asset.err_not_found');
  END IF;

  RETURN jsonb_build_object('id', p_id, 'status', 'classified');
END;
$function$;
COMMENT ON FUNCTION asset.classify(uuid,text,text,text[],integer,integer,text,text,text,text,text[]) IS 'Classify an asset: update metadata from Claude vision analysis, set status to classified';

CREATE OR REPLACE FUNCTION asset.data_assets(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_status   TEXT   := NULLIF(trim(COALESCE(p_params->>'p_status', '')), '');
  v_q        TEXT   := NULLIF(trim(COALESCE(p_params->>'q', '')), '');
  v_offset   INT    := coalesce((p_params->>'_offset')::int, 0);
  v_size     INT    := coalesce((p_params->>'_size')::int, 20);
  v_rows     JSONB;
  v_has_more BOOLEAN;
BEGIN
  SELECT coalesce(jsonb_agg(row), '[]') INTO v_rows
  FROM (
    SELECT jsonb_build_array(
      a.id,
      a.filename,
      COALESCE(a.title, '—'),
      a.mime_type,
      a.status,
      COALESCE(array_to_string(a.tags, ', '), ''),
      to_char(a.created_at, 'DD/MM/YYYY')
    ) AS row
    FROM asset.asset a
    WHERE (v_status IS NULL OR a.status = v_status)
      AND (v_q IS NULL OR a.search_vec @@ plainto_tsquery('pgv_search', v_q))
    ORDER BY a.created_at DESC
    LIMIT v_size + 1 OFFSET v_offset
  ) sub;

  v_has_more := jsonb_array_length(v_rows) > v_size;
  IF v_has_more THEN
    v_rows := v_rows - v_size;
  END IF;

  RETURN jsonb_build_object('rows', v_rows, 'has_more', v_has_more);
END;
$function$;
COMMENT ON FUNCTION asset.data_assets(jsonb) IS 'Data provider for pgv.table(): asset list with FTS, tag filter, status filter, cursor pagination';

CREATE OR REPLACE FUNCTION asset.get_asset(p_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  a       RECORD;
  v_body  TEXT;
  v_status_variant TEXT;
  v_tags  TEXT;
  v_colors TEXT;
  v_dl    TEXT[];
BEGIN
  SELECT * INTO a FROM asset.asset WHERE id = p_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION '%', pgv.t('asset.err_not_found');
  END IF;

  v_status_variant := CASE a.status
    WHEN 'classified' THEN 'success'
    WHEN 'to_classify' THEN 'warning'
    ELSE 'default'
  END;

  -- Breadcrumb
  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    pgv.t('asset.nav_assets'), '/',
    COALESCE(a.title, a.filename)
  ]);

  -- Image
  v_body := v_body
    || '<img src="' || pgv.esc(a.path) || '" style="max-width:100%;border-radius:8px" loading="lazy">';

  -- Tags as badges
  IF cardinality(a.tags) > 0 THEN
    v_tags := array_to_string(
      ARRAY(SELECT pgv.badge(t, 'default') FROM unnest(a.tags) AS t),
      ' ');
  ELSE
    v_tags := '-';
  END IF;

  -- Colors as inline swatches
  IF cardinality(a.colors) > 0 THEN
    v_colors := array_to_string(
      ARRAY(SELECT '<span style="display:inline-block;width:24px;height:24px;border-radius:4px;background:' || c || ';margin-right:4px;vertical-align:middle" title="' || c || '"></span>' FROM unnest(a.colors) AS c),
      '');
  ELSE
    v_colors := '-';
  END IF;

  -- Metadata DL
  v_dl := ARRAY[
    pgv.t('asset.field_title'), COALESCE(pgv.esc(a.title), '-'),
    pgv.t('asset.field_description'), COALESCE(pgv.esc(a.description), '-'),
    pgv.t('asset.field_filename'), pgv.esc(a.filename),
    pgv.t('asset.field_mime'), a.mime_type,
    pgv.t('asset.field_dimensions'), CASE WHEN a.width IS NOT NULL THEN a.width::text || ' × ' || a.height::text ELSE '-' END,
    pgv.t('asset.field_orientation'), COALESCE(a.orientation, '-'),
    pgv.t('asset.field_status'), pgv.badge(a.status, v_status_variant),
    pgv.t('asset.field_saison'), COALESCE(a.saison, '-'),
    pgv.t('asset.field_credit'), COALESCE(pgv.esc(a.credit), '-'),
    pgv.t('asset.field_usage_hint'), COALESCE(pgv.esc(a.usage_hint), '-'),
    pgv.t('asset.field_tags'), v_tags,
    pgv.t('asset.field_colors'), v_colors,
    pgv.t('asset.field_created'), to_char(a.created_at, 'DD/MM/YYYY HH24:MI'),
    pgv.t('asset.field_classified'), CASE WHEN a.classified_at IS NOT NULL THEN to_char(a.classified_at, 'DD/MM/YYYY HH24:MI') ELSE '-' END
  ];
  v_body := v_body || pgv.dl(VARIADIC v_dl);

  -- Actions
  v_body := v_body || '<p>';
  IF a.status = 'to_classify' THEN
    v_body := v_body || pgv.badge(pgv.t('asset.btn_classify'), 'warning') || ' ';
  END IF;
  v_body := v_body || pgv.action(
    pgv.t('asset.btn_delete'), 'post_asset_delete',
    jsonb_build_object('p_id', a.id),
    'secondary', pgv.t('asset.confirm_delete')
  );
  v_body := v_body || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION asset.get_asset(uuid) IS 'Asset detail page: breadcrumb, image, metadata (dl), tags, colors, actions';

CREATE OR REPLACE FUNCTION asset.get_index(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_total       INT;
  v_to_classify INT;
  v_classified  INT;
  v_status      TEXT;
  v_q           TEXT;
  v_body        TEXT;
  v_rows        TEXT[];
  v_row_count   INT := 0;
  v_status_label TEXT;
  v_dims        TEXT;
  r             RECORD;
BEGIN
  v_status := NULLIF(trim(COALESCE(p_params->>'status', '')), '');
  v_q := NULLIF(trim(COALESCE(p_params->>'q', '')), '');

  -- Stats (unfiltered)
  SELECT count(*)::int INTO v_total FROM asset.asset;
  SELECT count(*)::int INTO v_to_classify FROM asset.asset WHERE status = 'to_classify';
  SELECT count(*)::int INTO v_classified FROM asset.asset WHERE status = 'classified';

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('asset.stat_total'), v_total::text),
    pgv.stat(pgv.t('asset.stat_to_classify'), v_to_classify::text),
    pgv.stat(pgv.t('asset.stat_classified'), v_classified::text)
  ]);

  -- Filters
  v_body := v_body
    || '<form>'
    || '<div class="grid">'
    || pgv.sel('status', pgv.t('asset.field_status'), jsonb_build_array(
         jsonb_build_object('label', pgv.t('asset.filter_all'), 'value', ''),
         jsonb_build_object('label', pgv.t('asset.status_to_classify'), 'value', 'to_classify'),
         jsonb_build_object('label', pgv.t('asset.status_classified'), 'value', 'classified'),
         jsonb_build_object('label', pgv.t('asset.status_archived'), 'value', 'archived')
       ), COALESCE(v_status, ''))
    || pgv.input('q', 'search', pgv.t('asset.field_search'), v_q)
    || '</div>'
    || '<button type="submit" class="secondary">' || pgv.t('asset.btn_filter') || '</button>'
    || '</form>';

  IF v_total = 0 THEN
    v_body := v_body || pgv.empty(pgv.t('asset.empty_no_asset'), pgv.t('asset.empty_first_asset'));
  ELSE
    -- Table rows
    v_rows := ARRAY[
      '| | ' || pgv.t('asset.col_title') || ' | ' || pgv.t('asset.col_filename')
        || ' | ' || pgv.t('asset.col_mime') || ' | ' || pgv.t('asset.col_tags')
        || ' | ' || pgv.t('asset.col_status') || ' | ' || pgv.t('asset.field_dimensions') || ' |',
      '|---|---|---|---|---|---|---|'
    ];

    FOR r IN
      SELECT a.id, a.path, a.thumb_path, a.filename, a.title, a.status, a.tags,
             a.width, a.height, a.mime_type
      FROM asset.asset a
      WHERE (v_status IS NULL OR a.status = v_status)
        AND (v_q IS NULL OR a.search_vec @@ plainto_tsquery('pgv_search', v_q))
      ORDER BY a.created_at DESC
    LOOP
      v_status_label := CASE r.status
        WHEN 'classified' THEN pgv.badge(pgv.t('asset.status_classified'), 'success')
        WHEN 'to_classify' THEN pgv.badge(pgv.t('asset.status_to_classify'), 'warning')
        ELSE pgv.badge(r.status, 'default')
      END;

      v_dims := CASE WHEN r.width IS NOT NULL
        THEN r.width::text || '×' || r.height::text
        ELSE '—' END;

      v_rows := v_rows || (
        '| <img src="' || COALESCE(r.thumb_path, r.path) || '" style="height:40px;width:60px;object-fit:cover;border-radius:4px">'
        || ' | [' || pgv.esc(COALESCE(r.title, r.filename)) || '](/asset/asset?p_id=' || r.id || ')'
        || ' | ' || pgv.esc(r.filename)
        || ' | ' || r.mime_type
        || ' | ' || COALESCE(array_to_string(r.tags[1:4], ', '), '')
        || ' | ' || v_status_label
        || ' | ' || v_dims
        || ' |'
      );
      v_row_count := v_row_count + 1;
    END LOOP;

    IF v_row_count = 0 THEN
      v_body := v_body || pgv.empty(pgv.t('asset.empty_no_results'));
    ELSE
      v_body := v_body || '<md data-page="20">' || array_to_string(v_rows, E'\n') || '</md>';
    END IF;
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION asset.get_index(jsonb) IS 'Asset library: stats, filters, md table with thumb_path thumbnails linking to get_asset';

